export type Producto = {
  id: number;
  nombre: string;
  categoria: string;
  precio: number;
  descripcion?: string;
};

const API_BASE_URL = "http://localhost:8080/api";

export async function getMenu(): Promise<Producto[]> {
  try {
    const res = await fetch(`${API_BASE_URL}/menu`);
    if (!res.ok) throw new Error("Error al cargar el menú");
    return res.json();
  } catch (error) {
    // Mock data para desarrollo
    return [
      {
        id: 1,
        nombre: "Pizza Margherita",
        categoria: "Plato Principal",
        precio: 15.99,
      },
      { id: 2, nombre: "Ensalada César", categoria: "Entrada", precio: 8.5 },
      { id: 3, nombre: "Tiramisu", categoria: "Postre", precio: 6.99 },
    ];
  }
}

export async function agregarProducto(
  producto: Omit<Producto, "id">
): Promise<Producto> {
  try {
    const res = await fetch(`${API_BASE_URL}/menu`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(producto),
    });
    if (!res.ok) throw new Error(await res.text());
    return res.json();
  } catch (error) {
    // Mock para desarrollo
    console.log("Agregando producto (mock):", producto);
    return { ...producto, id: Date.now() };
  }
}

export async function eliminarProducto(id: number): Promise<void> {
  try {
    const res = await fetch(`${API_BASE_URL}/menu/${id}`, {
      method: "DELETE",
    });
    if (!res.ok) throw new Error("Error al eliminar el producto");
  } catch (error) {
    console.log("Eliminando producto (mock):", id);
  }
}

export async function editarProducto(
  id: number,
  producto: Omit<Producto, "id">
): Promise<Producto> {
  try {
    const res = await fetch(`${API_BASE_URL}/menu/${id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(producto),
    });
    if (!res.ok) throw new Error("Error al actualizar el producto");
    return res.json();
  } catch (error) {
    // Mock para desarrollo
    console.log("Editando producto (mock):", id, producto);
    return { ...producto, id };
  }
}
